pub fn rotate_right<T: Clone>(arr: &mut [T], k: usize) {
    let len = arr.len();
    if len == 0 { return; }
    let k = k % len;
    if k == 0 { return; }

    // Reverse the whole array
    arr.reverse();

    // Reverse first k elements (which were originally last k)
    let mut start = 0;
    let mut end = k - 1;
    while start < end {
        arr.swap(start, end);
        start += 1;
        end -= 1;
    }

    // Reverse the remaining elements
    start = k;
    let mut end = len - 1;
    while start < end {
        arr.swap(start, end);
        start += 1;
        end -= 1;
    }
}

